303 // Return true, if No Signed Wrap should be maintained for I.
304 // The No Signed Wrap flag can be kept if the operation "B (I.getOpcode) C",
305 // where both B and C should be ConstantInts, results in a constant that does
306 // not overflow. This function only handles the Add/Sub/Mul opcodes. For
307 // all other opcodes, the function conservatively returns false.
308 static bool maintainNoSignedWrap(BinaryOperator &I, Value *B, Value *C) {
309   auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
310   if (!OBO || !OBO->hasNoSignedWrap())
311     return false;
312 
313   const APInt *BVal, *CVal;
314   if (!match(B, m_APInt(BVal)) || !match(C, m_APInt(CVal)))
315     return false;
316 
317   // We reason about Add/Sub/Mul Only.
318   bool Overflow = false;
319   switch (I.getOpcode()) {
320   case Instruction::Add:
321     (void)BVal->sadd_ov(*CVal, Overflow);
322     break;
323   case Instruction::Sub:
324     (void)BVal->ssub_ov(*CVal, Overflow);
325     break;
326   case Instruction::Mul:
327     (void)BVal->smul_ov(*CVal, Overflow);
328     break;
329   default:
330     // Conservatively return false for other opcodes.
331     return false;
332   }
333   return !Overflow;
334 }
