361 /// Combine constant operands of associative operations either before or after a
362 /// cast to eliminate one of the associative operations:
363 /// (op (cast (op X, C2)), C1) --> (cast (op X, op (C1, C2)))
364 /// (op (cast (op X, C2)), C1) --> (op (cast X), op (C1, C2))
365 static bool simplifyAssocCastAssoc(BinaryOperator *BinOp1,
366                                    InstCombinerImpl &IC) {
367   auto *Cast = dyn_cast<CastInst>(BinOp1->getOperand(0));
368   if (!Cast || !Cast->hasOneUse())
369     return false;
370 
371   // TODO: Enhance logic for other casts and remove this check.
372   auto CastOpcode = Cast->getOpcode();
373   if (CastOpcode != Instruction::ZExt)
374     return false;
375 
376   // TODO: Enhance logic for other BinOps and remove this check.
377   if (!BinOp1->isBitwiseLogicOp())
378     return false;
379 
380   auto AssocOpcode = BinOp1->getOpcode();
381   auto *BinOp2 = dyn_cast<BinaryOperator>(Cast->getOperand(0));
382   if (!BinOp2 || !BinOp2->hasOneUse() || BinOp2->getOpcode() != AssocOpcode)
383     return false;
384 
385   Constant *C1, *C2;
386   if (!match(BinOp1->getOperand(1), m_Constant(C1)) ||
387       !match(BinOp2->getOperand(1), m_Constant(C2)))
388     return false;
389 
390   // TODO: This assumes a zext cast.
391   // Eg, if it was a trunc, we'd cast C1 to the source type because casting C2
392   // to the destination type might lose bits.
393 
394   // Fold the constants together in the destination type:
395   // (op (cast (op X, C2)), C1) --> (op (cast X), FoldedC)
396   const DataLayout &DL = IC.getDataLayout();
397   Type *DestTy = C1->getType();
398   Constant *CastC2 = ConstantFoldCastOperand(CastOpcode, C2, DestTy, DL);
399   if (!CastC2)
400     return false;
401   Constant *FoldedC = ConstantFoldBinaryOpOperands(AssocOpcode, C1, CastC2, DL);
402   if (!FoldedC)
403     return false;
404 
405   IC.replaceOperand(*Cast, 0, BinOp2->getOperand(0));
406   IC.replaceOperand(*BinOp1, 1, FoldedC);
407   BinOp1->dropPoisonGeneratingFlags();
408   Cast->dropPoisonGeneratingFlags();
409   return true;
410 }
