2100   CommonPointerBase Base;
2101 
2102   if (LHS->getType() != RHS->getType())
2103     return Base;
2104 
2105   // Collect all base pointers of LHS.
2106   SmallPtrSet<Value *, 16> Ptrs;
2107   Value *Ptr = LHS;
2108   while (true) {
2109     Ptrs.insert(Ptr);
2110     if (auto *GEP = dyn_cast<GEPOperator>(Ptr))
2111       Ptr = GEP->getPointerOperand();
2112     else
2113       break;
2114   }
2115 
2116   // Find common base and collect RHS GEPs.
2117   while (true) {
2118     if (Ptrs.contains(RHS)) {
2119       Base.Ptr = RHS;
2120       break;
2121     }
2122 
2123     if (auto *GEP = dyn_cast<GEPOperator>(RHS)) {
2124       Base.RHSGEPs.push_back(GEP);
2125       Base.RHSNW &= GEP->getNoWrapFlags();
2126       RHS = GEP->getPointerOperand();
2127     } else {
2128       // No common base.
2129       return Base;
2130     }
2131   }
2132 
2133   // Collect LHS GEPs.
2134   while (true) {
2135     if (LHS == Base.Ptr)
2136       break;
2137 
2138     auto *GEP = cast<GEPOperator>(LHS);
2139     Base.LHSGEPs.push_back(GEP);
2140     Base.LHSNW &= GEP->getNoWrapFlags();
2141     LHS = GEP->getPointerOperand();
2142   }
2143 
2144   return Base;
2145 }
